if ( ! function_exists( 'vitepos_get_product_cart_item' ) ) {
	/**
	 * The vitepos get product cart item is generated by appsbd
	 *
	 * @param int $product_id Its wc product or variation id.
	 *
	 * @return \VitePos_Lite\Libs\Cart_Item
	 */
	function vitepos_get_product_cart_item( $product_id ) {
		$product = wc_get_product( $product_id );
		if ( ! empty( $product ) ) {
			$cart_item = new \VitePos_Lite\Libs\Cart_Item();
			if ( $product->get_type() == 'variation' ) {
				$product_parent          = wc_get_product( $product->get_parent_id() );
				$cart_item->product_id   = $product_parent->get_id();
				$cart_item->product_name = $product_parent->get_name();
				$cart_item->variation_id = $product->get_id();
				$cart_item->variation_name = $product->get_name();

				foreach ( $product->get_variation_attributes( false ) as $key => $item ) {
					if ( ! empty( $item ) ) {
						$att_name         = wc_attribute_label( $key, $product );
						$cart_item->desc .= "<span>$att_name : <b>$item</b></span>";
					}
				}
			} elseif ( $product->get_type() == 'variable' ) {
				return null;
			} else {
				$cart_item->product_id   = $product->get_id();
				$cart_item->product_name = $product->get_name();
				$cart_item->variation_id = '';
			}
			$cart_item->purchase_cost = get_post_meta( $product->get_id(), '_cogs_total_value', true );
			$cart_item->price         = $product->get_price();
			$cart_item->regular_price = $product->get_regular_price();
			$cart_item->manage_stock = $product->get_manage_stock();
			$cart_item->barcode       = vitepos_apply_filters( 'vitepos/filter/get-product-barcode', $product );
			$cart_item->image         = \VitePos_Lite\Libs\POS_Product::get_wc_product_image(
				$product,
				'woocommerce_thumbnail'
			);
			$cart_item->stock_quantity = ! empty( $product->get_stock_quantity() ) ? $product->get_stock_quantity() : 0;
			if ( ! vitepos_apply_filters( 'woocommerce_prices_include_tax', get_option( 'woocommerce_prices_include_tax' ) === 'yes' ) ) {
				$cart_item->tax       = NumberUtil::round(
					( wc_get_price_including_tax( $product ) - $cart_item->price ),
					wc_get_price_decimals()
				);
				$cart_item->tax_class = $product->get_tax_class();
				vitepos_product_tax_rates( $cart_item );
			}
			return $cart_item;
		}

		return null;
	}
}
if ( ! function_exists( 'vitepos_product_tax_rates' ) ) {
	/**
	 * The vtp product tax rates is generated by appsbd
	 *
	 * @param \VitePos_Lite\Libs\Cart_Item $item It is product param.
	 */
	function vitepos_product_tax_rates( &$item ) {
		$tax_rates = \WC_Tax::get_rates( $item->tax_class );

		foreach ( $tax_rates as $rate ) {
			$item->tax_rates[] = array(
				'label' => $rate['label'],
				'rate'  => $rate['rate'],
			);
		}
		$taxes      = \WC_Tax::calc_tax(
			$item->price,
			$tax_rates,
			false
		);
		$tax_amount = array_sum( $taxes );
		$item->tax  = $tax_amount;
	}
}
if ( ! function_exists( 'vitepos_get_product_by_barcode' ) ) {
	/**
	 * The vitepos get product by barcode is generated by appsbd
	 *
	 * @param mixed $barcode It is barcode param.
	 * @param mixed $prop It is prop param.
	 *
	 * @return \VitePos_Lite\Libs\Cart_Item|null
	 */
	function vitepos_get_product_by_barcode( $barcode, $prop = '' ) {
		$product_id = null;
		if ( ! empty( $prop ) ) {
			$barcode_type = $prop;
		} else {
			$barcode_type = \VitePos_Lite\Modules\POS_Settings::get_module_option( 'barcode_field', '' );
		}
		$barcode_type = strtoupper( $barcode_type );
		if ( 'CUS' == $barcode_type ) {
			$args          = array(
				'limit'      => 1,
				'status'     => 'publish',
				'orderby'    => 'date',
				'order'      => 'DESC',
				'post_type'  => array( 'product', 'product_variation' ),
				'meta_query' => array(
					array(
						'key'     => '_vt_barcode',
						'value'   => $barcode,
						'compare' => '=',
					),
				),
			);
			$product_query = new \WP_Query( $args );
			if ( $product_query->found_posts > 0 ) {
				$product_id = $product_query->posts[0]->ID;
			}
		} elseif ( 'SKU' == $barcode_type ) {
			$args          = array(
				'limit'      => 1,
				'status'     => 'publish',
				'orderby'    => 'date',
				'order'      => 'DESC',
				'post_type'  => array( 'product', 'product_variation' ),
				'meta_query' => array(
					array(
						'key'     => '_sku',
						'value'   => $barcode,
						'compare' => '=',
					),
				),
			);
			$product_query = new \WP_Query( $args );
			if ( $product_query->found_posts > 0 ) {
				$product_id = $product_query->posts[0]->ID;
			}
		} elseif ( 'GUI' == $barcode_type ) {
			$args          = array(
				'limit'      => 1,
				'status'     => 'publish',
				'orderby'    => 'date',
				'order'      => 'DESC',
				'post_type'  => array( 'product', 'product_variation' ),
				'meta_query' => array(
					array(
						'key'     => '_global_unique_id',
						'value'   => $barcode,
						'compare' => '=',
					),
				),
			);
			$product_query = new \WP_Query( $args );
			if ( $product_query->found_posts > 0 ) {
				$product_id = $product_query->posts[0]->ID;
			}
		} else {

			$product_id = (int) preg_replace( '#[^0-9]#', '', $barcode );
		}
		if ( ! empty( $product_id ) ) {
			return vitepos_get_product_cart_item( $product_id );
		}
		return null;
	}
}

if ( ! function_exists( 'vitepos_number_format' ) ) {
	/**
	 * The vitepos price only is generated by appsbd
	 *
	 * @param mixed  $price This is price value.
	 *
	 * @param string $dec_point Its is decimal point.
	 * @param string $thousand_sep Its thousand separator.
	 *
	 * @return mixed|string
	 */
	function vitepos_number_format( $price, $dec_point = '.', $thousand_sep = '' ) {

			$decimals = wc_get_price_decimals();

		$original_price = $price;

		$price = (float) $price;

		$negative = $price < 0;

		/**
		 * Filter raw price.
		 *
		 * @since 1.0.0
		 * @param float        $raw_price      Raw price.
		 * @param float|string $original_price Original price as float, or empty string. Since 5.0.0.
		 */
		$price = vitepos_apply_filters( 'raw_woocommerce_price', $negative ? $price * -1 : $price, $original_price );

		/**
		 * Filter formatted price.
		 *
		 * @since v1.0.0
		 * @param float        $formatted_price    Formatted price.
		 * @param float        $price              Unformatted price.
		 * @param int          $decimals           Number of decimals.
		 * @param string       $decimal_separator  Decimal separator.
		 * @param string       $thousand_separator Thousand separator.
		 * @param float|string $original_price     Original price as float, or empty string. Since 5.0.0.
		 */
		$price = vitepos_apply_filters( 'formatted_woocommerce_price', number_format( $price, $decimals, $dec_point, $thousand_sep ), $price, $decimals, $dec_point, $thousand_sep, $original_price );

		/**
		 * Filter formatted price.
		 *
		 * @since v1.0.0
		 */
		if ( vitepos_apply_filters( 'woocommerce_price_trim_zeros', false ) && $decimals > 0 ) {
			$price = wc_trim_zeros( $price );
		}
		return (float) $price;
	}

	if ( ! function_exists( 'vitepos_get_select_option' ) ) {
		/**
		 * The appsbd get select option is generated by appsbd
		 *
		 * @param mixed  $value Its value.
		 * @param mixed  $text Its text field.
		 * @param string $selected Its selected filed.
		 * @param array  $attr Its extra attributes.
		 */
		function vitepos_get_select_option( $value, $text, $selected = '', $attr = array() ) {

			$attr_str = '';
			if ( is_array( $attr ) && count( $attr ) > 0 ) {
				foreach ( $attr as $key => $kvalue ) {
					$attr_str .= ' ' . $key . '="' . $kvalue . '"';
				}
			}
			if ( is_array( $selected ) ) {
				$is_selected = in_array( $value, $selected );
			} else {
				$is_selected = $selected == $value;
			}
			?>
			<option <?php echo esc_attr( $attr_str ); ?> <?php echo esc_attr( $is_selected ? ' selected ' : '' ); ?>
				value="<?php echo esc_attr( $value ); ?>"><?php echo wp_kses_post( $text ); ?></option>
			<?php
		}
	}
	if ( ! function_exists( 'vitepos_get_select_options' ) ) {
		/**
		 * The appsbd get select options is generated by appsbd
		 *
		 * @param array  $options Its the options array.
		 * @param string $selected Its selected option.
		 * @param array  $attr Its extra attributes.
		 */
		function vitepos_get_select_options( $options, $selected = '', $attr = array() ) {
			if ( is_array( $options ) ) {
				foreach ( $options as $key => $value ) {
					if ( is_array( $selected ) ) {
						vitepos_get_select_option( $key, $value, ( in_array( $key, $selected ) ? $key : '' ), $attr );
					} else {
						vitepos_get_select_option( $key, $value, $selected, $attr );
					}
				}
			}
		}
	}
}

if ( ! function_exists( 'vitepos_is_rest' ) ) {
	/**
	 * The vitepos is rest is generated by appsbd
	 *
	 * @param array $routes its routes param.
	 *
	 * @return bool
	 */
	function vitepos_is_rest( $routes = array() ) {
		if ( appsbd_is_rest() ) {
			if ( empty( $routes ) ) {
				return true;
			} else {
				$current = '';
				if ( ! empty( $_SERVER['REQUEST_URI'] ) ) {
					$current = esc_url_raw( wp_unslash( $_SERVER['REQUEST_URI'] ) );
				}
				if ( ! empty( $current ) ) {
					foreach ( $routes as $route ) {
						if ( strpos( $current, $route ) !== false ) {
							return true;
						}
					}
				}
			}
		}

		return false;
	}
}
if ( ! function_exists( 'vitepos_wc_amount' ) ) {
	/**
	 * The vitepos wc amount is generated by appsbd
	 *
	 * @param mixed $amount Its amount param.
	 *
	 * @return float
	 */
	function vitepos_wc_amount( $amount ) {
		$amount   = (float) $amount;
		$decimals = wc_get_price_decimals();
		return round( $amount, $decimals );
	}
}

if ( ! function_exists( 'vitepos_apply_filters' ) ) {
	/**
	 * The vitepos apply filters is generated by appsbd
	 *
	 * @param mixed ...$params Hook parameters.
	 *
	 * @return mixed
	 */
	function vitepos_apply_filters( ...$params ) {

		/**
		 * Fires a dynamic hook inside vitepos_apply_filters().
		 *
		 * @since 3.3.1
		 *
		 * @param string $vitepos_name The dynamic hook name to be fired.
		 * @param mixed  ...$params Additional parameters passed to the hook.
		 *
		 * phpcs:ignore WordPress.NamingConventions.PrefixAllGlobals.NonPrefixedHooknameFound
		 */
		return call_user_func_array( 'apply_filters', $params );
	}

}
